  "Support": { "zh-CN": "支持", en: "Support", ja: "サポート", ko: "지원", fr: "Support" },
  "Creators": { "zh-CN": "创作者", en: "Creators", ja: "クリエイター", ko: "크리에이터", fr: "Créateurs" },
