  "Relationship vocabulary": { "zh-CN": "关系词汇", en: "Relationship vocabulary", ja: "関係の語彙", ko: "관계 용어", fr: "Vocabulaire des relations" },
  "Relationship vocabulary display for blocks, depends_on, verifies, reviews, refreshes, and related edges.": { "zh-CN": "针对 blocks、depends_on、verifies、reviews、refreshes 和 related 边的关系词汇显示。", en: "Relationship vocabulary display for blocks, depends_on, verifies, reviews, refreshes, and related edges.", ja: "blocks、depends_on、verifies、reviews、refreshes、related の各エッジに対する関係語彙の表示。", ko: "blocks, depends_on, verifies, reviews, refreshes, related 엣지에 대한 관계 용어 표시.", fr: "Affichage du vocabulaire des relations pour les arêtes blocks, depends_on, verifies, reviews, refreshes et related." },
  "Release accepted": { "zh-CN": "发布已接受", en: "Release accepted", ja: "リリース承認済み", ko: "릴리스 승인됨", fr: "Version acceptée" },
  "Rendered DS review": { "zh-CN": "已渲染的 DS 审查", en: "Rendered DS review", ja: "レンダリング済みの DS レビュー", ko: "렌더링된 DS 검토", fr: "Revue DS rendue" },
  "Rendered fixture selectors": { "zh-CN": "已渲染夹具的选择器", en: "Rendered fixture selectors", ja: "レンダリング済みフィクスチャのセレクター", ko: "렌더링된 픽스처 셀렉터", fr: "Sélecteurs de fixture rendus" },
  "Rendered proof and QA summary": { "zh-CN": "已渲染的证明与 QA 摘要", en: "Rendered proof and QA summary", ja: "レンダリング済みの証明と QA サマリー", ko: "렌더링된 증명 및 QA 요약", fr: "Preuve rendue et résumé QA" },
  "Replacing with an activity log.": { "zh-CN": "用活动日志替代。", en: "Replacing with an activity log.", ja: "アクティビティログで置き換えること。", ko: "활동 로그로 대체하기.", fr: "Remplacer par un journal d'activité." },
  "Replacing with an execution route.": { "zh-CN": "用执行路由替代。", en: "Replacing with an execution route.", ja: "実行ルートで置き換えること。", ko: "실행 라우트로 대체하기.", fr: "Remplacer par une route d'exécution." },
  "Required Storybook chapters": { "zh-CN": "必需的 Storybook 章节", en: "Required Storybook chapters", ja: "必須の Storybook チャプター", ko: "필수 Storybook 챕터", fr: "Chapitres Storybook requis" },
  "Required locales and dark theme token override for local contract proof.": { "zh-CN": "本地契约证明所需的语言环境和暗色主题 token 覆盖。", en: "Required locales and dark theme token override for local contract proof.", ja: "ローカル契約証明に必要なロケールとダークテーマ token のオーバーライド。", ko: "로컬 계약 증명에 필요한 로케일 및 다크 테마 token 재정의.", fr: "Locales requises et surcharge de token de thème sombre pour la preuve de contrat local." },
  "Required readback": { "zh-CN": "必需的回读", en: "Required readback", ja: "必須のリードバック", ko: "필수 리드백", fr: "Relecture requise" },
